def solve(d: date) -> str:
    """
    Returns the next Friday on or after d as a string in ISO format.
    """
    # If d is already Friday (weekday 4), return it; otherwise find next Friday
    if d.weekday() == 4:
        return d.isoformat()
    else:
        # Calculate days until next Friday
        days_ahead = (4 - d.weekday()) % 7
        if days_ahead == 0:
            days_ahead = 7
        next_friday = d + relativedelta(days=days_ahead)
        return next_friday.isoformat()
