def solve(data: list) -> str:
    from tabulate import tabulate

    if not data:
        return ""

    # Determine headers and rows
    # If first element is a list/tuple of strings, treat as headers
    # Otherwise, use "firstrow" if first row looks like headers
    # For simplicity, assume no headers unless specified

    headers = []
    rows = data

    # Check if data has headers as first row (all strings)
    if data and all(isinstance(x, str) for x in data[0]):
        headers = list(data[0])
        rows = data[1:]

    # Determine per-column alignment based on data types
    if rows:
        num_cols = max(len(row) for row in rows) if rows else 0
        colaligns = []
        for col_idx in range(num_cols):
            # Check column types
            is_numeric = True
            for row in rows:
                if col_idx < len(row):
                    val = row[col_idx]
                    if val is None or val == "":
                        continue
                    try:
                        float(val)
                    except (ValueError, TypeError):
                        is_numeric = False
                        break
            if is_numeric:
                colaligns.append("right")
            else:
                colaligns.append("left")
    else:
        colaligns = None

    result = tabulate(rows, headers=headers, tablefmt="simple", colalign=colaligns)
    return result
