import tabulate

def solve(rows: list) -> str:
    if not rows:
        return ""

    # Find the maximum score in each column (assuming first column is name/label)
    # Assuming rows are lists where first element is a label and rest are scores
    num_cols = len(rows[0])
    max_scores = [float('-inf')] * num_cols

    for row in rows:
        for i in range(1, num_cols):
            if isinstance(row[i], (int, float)):
                max_scores[i] = max(max_scores[i], row[i])

    # Normalize scores to percentages
    normalized_rows = []
    for row in rows:
        normalized_row = [row[0]]
        for i in range(1, num_cols):
            if isinstance(row[i], (int, float)) and max_scores[i] > 0:
                percentage = (row[i] / max_scores[i]) * 100
                normalized_row.append(f"{percentage:.2f}%")
            else:
                normalized_row.append(row[i])
        normalized_rows.append(normalized_row)

    # Format using tabulate
    return tabulate.tabulate(normalized_rows, headers="firstrow", tablefmt="grid")
