def solve(rows: list) -> str:
    from tabulate import tabulate

    if not rows:
        return ""

    # Calculate column sums
    num_cols = len(rows[0])
    col_sums = [0.0] * num_cols
    for row in rows:
        for j in range(num_cols):
            col_sums[j] += float(row[j])

    # Normalize each row to percentages
    normalized = []
    for row in rows:
        new_row = []
        for j in range(num_cols):
            if col_sums[j] != 0:
                new_row.append(f"{float(row[j]) / col_sums[j] * 100:.2f}%")
            else:
                new_row.append("0.00%")
        normalized.append(new_row)

    return tabulate(normalized, tablefmt="plain")
